package org.apache.commons.compress.archivers.tar;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.compress.archivers.tar.steps"
)
public class CucumberTest {
}

package org.apache.commons.compress.archivers.tar.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.compress.archivers.tar.TarArchiveEntry;
import static org.junit.Assert.assertFalse;
import static org.junit.Assert.assertTrue;

public class StepDefs {

    private TarArchiveEntry entry;

    @Given("a TarArchiveEntry with name {string}")
    public void a_tar_archive_entry_with_name(String name) {
        entry = new TarArchiveEntry(name);
    }

    @Given("the entry link flag is {string} (Pax Extended Header)")
    public void the_entry_link_flag_is_pax_extended_header(String flag) {
        if (flag.equals("x")) {
            entry.setLinkFlag(TarArchiveEntry.LF_PAX_EXTENDED_HEADER);
        }
    }

    @Given("the entry link flag is {string} (Global Pax Extended Header)")
    public void the_entry_link_flag_is_global_pax_extended_header(String flag) {
        if (flag.equals("g")) {
            entry.setLinkFlag(TarArchiveEntry.LF_GNU_VOLHDR);
        }
    }

    @Given("the entry link flag is {string} (SunOS Pax Extended Header)")
    public void the_entry_link_flag_is_sunos_pax_extended_header(String flag) {
        if (flag.equals("X")) {
            // Use the appropriate flag for SunOS header (LF_XSTAR_LONGNAME or similar)
            entry.setLinkFlag((byte) 'X');
        }
    }

    @When("isDirectory is called")
    public void is_directory_is_called() {
        // The method will be called in the Then step
    }

    @Then("it should return false")
    public void it_should_return_false() {
        boolean isDir = false;
        try {
            isDir = entry.isDirectory();
        } catch (Exception e) {
            // Handle any exception that might occur
        }
        assertFalse("Entry should not be a directory", isDir);
    }
}

